const e=JSON.parse(`{"key":"v-3be6b4e6","path":"/read/papers/ai/XAI/selvaraju2017gradcam.html","title":"Grad-CAM","lang":"zh-CN","frontmatter":{"title":"Grad-CAM","order":2017,"icon":"icon-park:five-star-badge","description":"文章链接 基于梯度定位的深度网络视觉解释 0. 摘要 我们提出了一种从基于卷积神经网络( Convolutional Neural Network，CNN )的大型模型中为决策产生\\"视觉解释\\"的技术，使其更加透明。我们的方法- -梯度加权类激活映射( Gradient-weighted Class Activation Mapping，Grad-CAM )，使用任何目标概念(说logits是'狗' ,甚至是字幕)的梯度，流入最后的卷积层，产生一个突出图像中重要区域的粗定位图，用于预测概念。与以前的方法不同，Grad CAM适用于各种各样的CNN模型家族：( 1 )具有全连接层的CNN (例如：VGG )，( 2 )用于结构化输出(如字幕)的CNNs，( 3 )用于具有多模态输入(例如,视觉问答)或强化学习的任务，而不需要结构变化或重新训练。我们将Grad - CAM与现有的细粒度可视化相结合，创建了一种高分辨率的类别判别可视化Guided Grad-CAM，并将其应用于图像分类、图像描述和视觉问答( VQA )模型，包括基于ResNet的架构。在图像分类模型方面，我们的可视化( a )有助于深入了解这些模型的失败模式(表明看似不合理的预测有合理的解释)，( b )在ILSVRC - 15弱监督定位任务上优于以前的方法，( c )更忠实于底层模型，( d )通过识别数据集偏差帮助实现模型泛化。对于图像描述和VQA，我们的可视化显示即使非注意力模型也能定位输入。最后，我们设计并进行了人类研究，以衡量Grad - CAM解释是否有助于用户在深度网络的预测中建立适当的信任，并表明Grad - CAM帮助未经训练的用户成功地从一个\\"弱\\"的网络中识别出一个\\"强\\"的网络，即使两者都做出了相同的预测。我们的代码可在Github以及CloudCV上的演示[ 2 ] 1和Youtube网站上的视频获得。","head":[["meta",{"property":"og:url","content":"https://taochenyue.zone/read/papers/ai/XAI/selvaraju2017gradcam.html"}],["meta",{"property":"og:site_name","content":"TCY"}],["meta",{"property":"og:title","content":"Grad-CAM"}],["meta",{"property":"og:description","content":"文章链接 基于梯度定位的深度网络视觉解释 0. 摘要 我们提出了一种从基于卷积神经网络( Convolutional Neural Network，CNN )的大型模型中为决策产生\\"视觉解释\\"的技术，使其更加透明。我们的方法- -梯度加权类激活映射( Gradient-weighted Class Activation Mapping，Grad-CAM )，使用任何目标概念(说logits是'狗' ,甚至是字幕)的梯度，流入最后的卷积层，产生一个突出图像中重要区域的粗定位图，用于预测概念。与以前的方法不同，Grad CAM适用于各种各样的CNN模型家族：( 1 )具有全连接层的CNN (例如：VGG )，( 2 )用于结构化输出(如字幕)的CNNs，( 3 )用于具有多模态输入(例如,视觉问答)或强化学习的任务，而不需要结构变化或重新训练。我们将Grad - CAM与现有的细粒度可视化相结合，创建了一种高分辨率的类别判别可视化Guided Grad-CAM，并将其应用于图像分类、图像描述和视觉问答( VQA )模型，包括基于ResNet的架构。在图像分类模型方面，我们的可视化( a )有助于深入了解这些模型的失败模式(表明看似不合理的预测有合理的解释)，( b )在ILSVRC - 15弱监督定位任务上优于以前的方法，( c )更忠实于底层模型，( d )通过识别数据集偏差帮助实现模型泛化。对于图像描述和VQA，我们的可视化显示即使非注意力模型也能定位输入。最后，我们设计并进行了人类研究，以衡量Grad - CAM解释是否有助于用户在深度网络的预测中建立适当的信任，并表明Grad - CAM帮助未经训练的用户成功地从一个\\"弱\\"的网络中识别出一个\\"强\\"的网络，即使两者都做出了相同的预测。我们的代码可在Github以及CloudCV上的演示[ 2 ] 1和Youtube网站上的视频获得。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-01T12:56:35.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-01T12:56:35.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Grad-CAM\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-03-01T12:56:35.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"0. 摘要","slug":"_0-摘要","link":"#_0-摘要","children":[]},{"level":2,"title":"1. 引言","slug":"_1-引言","link":"#_1-引言","children":[]},{"level":2,"title":"2. 相关工作","slug":"_2-相关工作","link":"#_2-相关工作","children":[]},{"level":2,"title":"3. 方法","slug":"_3-方法","link":"#_3-方法","children":[]}],"git":{"createdTime":1677663893000,"updatedTime":1677675395000,"contributors":[{"name":"TaoChenyue","email":"3038816978@qq.com","commits":2}]},"readingTime":{"minutes":11.91,"words":3574},"filePathRelative":"read/papers/ai/XAI/selvaraju2017gradcam.md","localizedDate":"2023年3月1日","excerpt":"<p><a href=\\"https://doi.org/10.1109/ICCV.2017.74\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">文章链接</a></p>\\n\\n<p>基于梯度定位的深度网络视觉解释</p>\\n<h2> 0. 摘要</h2>\\n<p>我们提出了一种从基于卷积神经网络( Convolutional Neural Network，CNN )的大型模型中为决策产生\\"视觉解释\\"的技术，使其更加透明。我们的方法- -梯度加权类激活映射( Gradient-weighted Class Activation Mapping，Grad-CAM )，使用任何目标概念(说logits是'狗' ,甚至是字幕)的梯度，流入最后的卷积层，产生一个突出图像中重要区域的粗定位图，用于预测概念。与以前的方法不同，Grad CAM适用于各种各样的CNN模型家族：( 1 )具有全连接层的CNN (例如：VGG )，( 2 )用于结构化输出(如字幕)的CNNs，( 3 )用于具有多模态输入(例如,视觉问答)或强化学习的任务，而不需要结构变化或重新训练。我们将Grad - CAM与现有的细粒度可视化相结合，创建了一种高分辨率的类别判别可视化Guided Grad-CAM，并将其应用于图像分类、图像描述和视觉问答( VQA )模型，包括基于ResNet的架构。在图像分类模型方面，我们的可视化( a )有助于深入了解这些模型的失败模式(表明看似不合理的预测有合理的解释)，( b )在ILSVRC - 15弱监督定位任务上优于以前的方法，( c )更忠实于底层模型，( d )通过识别数据集偏差帮助实现模型泛化。对于图像描述和VQA，我们的可视化显示即使非注意力模型也能定位输入。最后，我们设计并进行了人类研究，以衡量Grad - CAM解释是否有助于用户在深度网络的预测中建立适当的信任，并表明Grad - CAM帮助未经训练的用户成功地从一个\\"弱\\"的网络中识别出一个\\"强\\"的网络，即使两者都做出了相同的预测。我们的代码可在<a href=\\"https://github.com/ramprs/grad-cam/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">Github</a>以及CloudCV上的演示[ 2 ] 1和<a href=\\"https://youtu.be/COjUB9Izk6E\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">Youtube网站</a>上的视频获得。</p>","autoDesc":true}`);export{e as data};
